section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/mobile-ux-basics.json",
  "title": "Mobile UX Basics: Touch Design, Navigation, and Performance",
  "type": "object",
  "required": [
    "artefact_id",
    "touch_targets",
    "thumb_zones",
    "navigation_pattern",
    "performance_budget",
    "platform_conventions",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "touch_targets": {
      "type": "object",
      "description": "minimum size + spacing per platform"
    },
    "thumb_zones": {
      "type": "object",
      "description": "primary action placement rules"
    },
    "navigation_pattern": {
      "type": "string",
      "description": "tab-bar / drawer / bottom-sheet decision",
      "minLength": 1
    },
    "performance_budget": {
      "type": "object",
      "description": "LCP / INP / payload thresholds"
    },
    "platform_conventions": {
      "type": "object",
      "description": "iOS vs Android divergences"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
